package main

import (
	"html/template"
	"net/http"
)

type Comment struct {
	Username string
	Comment  template.HTML
}

func main() {
	http.HandleFunc("/", commentHandler)
	http.ListenAndServe(":8080", nil)
}

func commentHandler(w http.ResponseWriter, r *http.Request) {
	comments := []Comment{
		{Username: "Alice", Comment: `<p>Hello! This is a <strong>comment</strong>.</p>`},
		{Username: "Bob", Comment: `<p>This is another <em>comment</em>.</p>`},
	}

	tmpl := template.Must(template.New("comments").Parse(`
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Comments</title>
</head>
<body>
    <h1>User Comments</h1>
    <ul>
        {{range .}}
        <li><strong>{{.Username}}</strong>: {{.Comment}}</li>
        {{end}}
    </ul>
</body>
</html>
	`))

	err := tmpl.Execute(w, comments)
	if err != nil {
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
	}
}